import{_ as t,o as n,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Einführung","description":"","frontmatter":{},"headers":[],"relativePath":"de/getting-started/introduction.md","filePath":"de/getting-started/introduction.md"}'),a={name:"de/getting-started/introduction.md"};function d(l,e,s,o,u,h){return n(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="einfuhrung" tabindex="-1">Einführung <a class="header-anchor" href="#einfuhrung" aria-label="Permalink to &quot;Einführung&quot;">​</a></h1><p>MyCompanyDesk ist eine All-in-One-Plattform für Buchhaltung und Geschäftsverwaltung, die für Freiberufler, Kleinunternehmen und Verwalter von Mietobjekten entwickelt wurde. Sie hilft Ihnen, Ihren gesamten Finanzworkflow zu verwalten — von der Rechnungserstellung und Ausgabenverfolgung bis zur USt.-Meldung und Kundenverwaltung.</p><h2 id="was-konnen-sie-mit-mycompanydesk-tun" tabindex="-1">Was können Sie mit MyCompanyDesk tun? <a class="header-anchor" href="#was-konnen-sie-mit-mycompanydesk-tun" aria-label="Permalink to &quot;Was können Sie mit MyCompanyDesk tun?&quot;">​</a></h2><ul><li><strong>Rechnungen erstellen und versenden</strong> — Professionelle Rechnungen mit Zahlungslinks, PDF-Generierung und E-Mail-Zustellung</li><li><strong>Ausgaben verfolgen</strong> — Ausgaben manuell erfassen oder Belege mit KI-gestützter OCR scannen</li><li><strong>Kunden verwalten</strong> — Eine vollständige Kundendatenbank mit Kontaktdaten und Verlauf pflegen</li><li><strong>Angebote erstellen</strong> — Angebote erstellen und bei Annahme in Rechnungen umwandeln</li><li><strong>Projekte verwalten</strong> — Arbeit in Projekte organisieren, Zeit erfassen und Rentabilität überwachen</li><li><strong>Verträge verwalten</strong> — Wiederkehrende Dienstleistungs- oder Mietverträge einrichten</li><li><strong>Vermögenswerte verfolgen</strong> — Mietobjekte, Fahrzeuge und Ausstattung verwalten</li><li><strong>Abrechnung automatisieren</strong> — Wiederkehrende Rechnungen und Ausgaben einrichten</li><li><strong>Berichte anzeigen</strong> — Umsatz, Gewinn, Cashflow, USt. und Kundenanalysen</li><li><strong>Zusammenarbeiten</strong> — Teammitglieder einladen, Berechtigungen festlegen und mit Ihrem Steuerberater teilen</li></ul><h2 id="unterstutzte-sprachen" tabindex="-1">Unterstützte Sprachen <a class="header-anchor" href="#unterstutzte-sprachen" aria-label="Permalink to &quot;Unterstützte Sprachen&quot;">​</a></h2><p>MyCompanyDesk ist vollständig verfügbar in:</p><ul><li>English</li><li>Nederlands (Dutch)</li><li>Deutsch (German)</li><li>Français (French)</li></ul><p>Sie können die Sprache jederzeit in Ihren Profileinstellungen wechseln. Rechnungen und E-Mails können in jeder dieser Sprachen versendet werden, unabhängig von Ihrer Oberflächensprache.</p><h2 id="tarife" tabindex="-1">Tarife <a class="header-anchor" href="#tarife" aria-label="Permalink to &quot;Tarife&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funktion</th><th>Free</th><th>Pro</th><th>Business</th></tr></thead><tbody><tr><td>Rechnungen &amp; Angebote</td><td>Begrenzt</td><td>Unbegrenzt</td><td>Unbegrenzt</td></tr><tr><td>Kunden</td><td>Begrenzt</td><td>Unbegrenzt</td><td>Unbegrenzt</td></tr><tr><td>Ausgabenverfolgung</td><td>Basis</td><td>Vollständig</td><td>Vollständig</td></tr><tr><td>Belegscanner</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>KI-Vorschläge</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Individuelles Branding</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Teammitglieder</td><td>1</td><td>Bis zu 5</td><td>Unbegrenzt</td></tr><tr><td>Berichte &amp; Export</td><td>Basis</td><td>Vollständig</td><td>Vollständig</td></tr><tr><td>API-Zugang</td><td>-</td><td>-</td><td>Ja</td></tr></tbody></table><h2 id="hilfe-erhalten" tabindex="-1">Hilfe erhalten <a class="header-anchor" href="#hilfe-erhalten" aria-label="Permalink to &quot;Hilfe erhalten&quot;">​</a></h2><ul><li>Nutzen Sie den <strong>kontextbezogenen Leitfaden</strong> (das Hilfe-Symbol in der App) für kontextbezogene Unterstützung</li><li>Durchsuchen Sie diese Dokumentation für detaillierte Funktionsanleitungen</li><li>Kontaktieren Sie den Support über das In-App-Ticketsystem</li></ul><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Bereit loszulegen? Gehen Sie zu <a href="/de/getting-started/create-account">Konto erstellen</a>, um Ihren Arbeitsbereich einzurichten.</p>',14)])])}const m=t(a,[["render",d]]);export{c as __pageData,m as default};
